import 'package:flutter/material.dart';
import 'package:pooja_sindhu/core/theme/app_colors.dart';
import 'package:pooja_sindhu/core/theme/app_spacing.dart';
class AppPrimaryButton extends StatelessWidget { const AppPrimaryButton({super.key, required this.label, this.onPressed, this.isLoading = false, this.fullWidth = true}); final String label; final VoidCallback? onPressed; final bool isLoading; final bool fullWidth; @override Widget build(BuildContext context) { final button = ElevatedButton(onPressed: isLoading ? null : onPressed, style: ElevatedButton.styleFrom(backgroundColor: AppColors.primary, foregroundColor: AppColors.onPrimary, minimumSize: const Size(48, 52), padding: const EdgeInsets.symmetric(horizontal: AppSpacing.xl, vertical: AppSpacing.md)), child: isLoading ? const SizedBox(width: 20, height: 20, child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white)) : Text(label)); return Semantics(label: isLoading ? 'Loading' : label, button: true, child: fullWidth ? SizedBox(width: double.infinity, child: button) : button); } }
